import React, { useState, useEffect } from 'react';
import axios from 'axios'; // Ensure axios is installed: npm install axios
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const ModelAccuracy = () => {
  const [performanceData, setPerformanceData] = useState([]);

  useEffect(() => {
    // Replace this URL with your actual Node.js or Flask endpoint
    axios.get('http://localhost:5000/api/model-performance')
      .then((response) => {
        // Set the real-time data into your state
        setPerformanceData(response.data);
      })
      .catch((error) => {
        console.error("Error fetching model metrics:", error);
      });
  }, []);

  return (
    <div style={{ padding: '20px', background: '#fff', borderRadius: '8px' }}>
      <h2>Real-Time Model Performance</h2>
      <ResponsiveContainer width="100%" height={300}>
        <BarChart data={performanceData}>
          <XAxis dataKey="model_name" />
          <YAxis domain={[0, 1]} />
          <Tooltip />
          <Legend />
          <Bar dataKey="accuracy" fill="#4caf50" name="Accuracy (R²)" />
          <Bar dataKey="error" fill="#f44336" name="Error (RMSE)" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ModelAccuracy;
